import React from "react";

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;

  return (
    <>
      <style>{`
        .hero-section {
          min-height: 100vh;
          display: flex;
          flex-direction: column;
          justify-content: center;
          padding: 100px clamp(1.25rem, 5vw, 4rem) clamp(3rem, 5vw, 5rem);
          position: relative;
          overflow: hidden;
        }
        .hero-inner {
          max-width: 860px;
          position: relative;
          z-index: 1;
          width: 100%;
        }
        .hero-badge {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: rgba(0,229,255,0.08);
          border: 1px solid rgba(0,229,255,0.2);
          border-radius: 99px;
          padding: 5px 14px;
          margin-bottom: 1.25rem;
        }
        .hero-name {
          font-family: var(--font-display);
          font-weight: 800;
          line-height: 1.05;
          letter-spacing: -0.03em;
          margin-bottom: 0.6rem;
          font-size: clamp(2.4rem, 5.5vw, 5rem);
          word-break: break-word;
          hyphens: auto;
        }
        .hero-sub {
          font-family: var(--font-display);
          font-weight: 600;
          color: var(--muted);
          margin-bottom: 0.9rem;
          font-size: clamp(0.82rem, 1.6vw, 1.15rem);
          line-height: 1.5;
          flex-wrap: wrap;
          word-break: break-word;
        }
        .hero-tagline {
          font-size: clamp(0.85rem, 1.4vw, 1rem);
          color: var(--muted);
          max-width: 500px;
          line-height: 1.75;
          margin-bottom: 2rem;
        }
        .hero-btns {
          display: flex;
          gap: 0.75rem;
          flex-wrap: wrap;
          margin-bottom: 0;
        }
        .btn-primary {
          background: var(--accent);
          color: #000;
          padding: 11px 24px;
          border-radius: 99px;
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.78rem, 1.1vw, 0.88rem);
          letter-spacing: 0.02em;
          transition: transform 0.2s, box-shadow 0.2s;
          display: inline-flex;
          align-items: center;
          gap: 6px;
          text-decoration: none;
          white-space: nowrap;
        }
        .btn-outline {
          background: transparent;
          color: var(--text);
          padding: 11px 24px;
          border-radius: 99px;
          border: 1px solid var(--border);
          font-family: var(--font-display);
          font-weight: 600;
          font-size: clamp(0.78rem, 1.1vw, 0.88rem);
          transition: border-color 0.2s, color 0.2s;
          text-decoration: none;
          white-space: nowrap;
        }
        .stats-wrap {
          max-width: 860px;
          width: 100%;
          position: relative;
          z-index: 1;
        }
        .stats-bar {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 1px;
          margin-top: clamp(2rem, 5vw, 3.5rem);
          background: var(--border);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          overflow: hidden;
          width: 100%;
        }
        .stat-cell {
          background: var(--surface);
          padding: clamp(0.85rem, 2vw, 1.25rem) clamp(0.5rem, 1.5vw, 1rem);
          text-align: center;
          transition: background 0.2s;
          min-width: 0;
        }
        .stat-val {
          font-family: var(--font-display);
          font-size: clamp(1.2rem, 2.5vw, 2rem);
          font-weight: 800;
          color: var(--accent);
          line-height: 1;
          white-space: nowrap;
        }
        .stat-lbl {
          font-size: clamp(0.58rem, 0.9vw, 0.72rem);
          color: var(--muted);
          margin-top: 5px;
          font-weight: 500;
          line-height: 1.3;
        }

        /* Tablet 768–1024 */
        @media (max-width: 1024px) {
          .hero-name { font-size: clamp(2.4rem, 6.5vw, 4rem); }
          .hero-section { padding: 90px clamp(1.25rem, 4vw, 2.5rem) 3rem; }
        }

        /* Small tablet / large mobile 480–768 */
        @media (max-width: 768px) {
          .hero-name { font-size: clamp(2.2rem, 8vw, 3.5rem); }
          .hero-section { padding: 80px 1.5rem 2.5rem; }
          .stats-bar { grid-template-columns: repeat(2, 1fr); }
        }

        /* Mobile < 480 */
        @media (max-width: 480px) {
          .hero-section { padding: 80px 1.25rem 2.5rem; min-height: auto; }
          .hero-name { font-size: clamp(2rem, 10vw, 2.8rem); line-height: 1.1; }
          .hero-btns { flex-direction: column; }
          .btn-primary, .btn-outline { width: 100%; justify-content: center; font-size: 0.875rem; }
          .stats-bar { grid-template-columns: repeat(2, 1fr); }
          .stat-val { font-size: 1.4rem; }
          .stat-lbl { font-size: 0.62rem; }
        }

        /* Very small < 360 */
        @media (max-width: 360px) {
          .hero-name { font-size: 1.85rem; }
          .hero-sub { font-size: 0.78rem; }
        }
      `}</style>

      <section className="hero-section" id="about">
        {/* BG blobs */}
        <div style={{ position:"absolute", top:"-10%", right:"-5%", width:"clamp(180px,35vw,480px)", height:"clamp(180px,35vw,480px)", borderRadius:"50%", background:"radial-gradient(circle, rgba(124,58,237,0.12) 0%, transparent 70%)", pointerEvents:"none" }} />
        <div style={{ position:"absolute", bottom:"0%", left:"-10%", width:"clamp(140px,28vw,360px)", height:"clamp(140px,28vw,360px)", borderRadius:"50%", background:"radial-gradient(circle, rgba(0,229,255,0.08) 0%, transparent 70%)", pointerEvents:"none" }} />

        <div className="hero-inner">
          {/* Badge */}
          <div className="hero-badge">
            <span style={{ width:7, height:7, borderRadius:"50%", background:"var(--accent)", animation:"pulse-ring 2s infinite", flexShrink:0 }} />
            <span style={{ fontSize:"0.7rem", color:"var(--accent)", fontWeight:600, fontFamily:"var(--font-display)", letterSpacing:"0.06em", textTransform:"uppercase", whiteSpace:"nowrap" }}>
              Open to Opportunities
            </span>
          </div>

          {/* Name */}
          <h1 className="hero-name">
            {name.split(" ")[0]}{" "}
            <span style={{ background:"linear-gradient(90deg, var(--accent), var(--accent2))", WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent", backgroundClip:"text" }}>
              {name.split(" ")[1]}
            </span>
          </h1>

          {/* Subtitle */}
          <p className="hero-sub">
            {title} · <span style={{ color:"var(--accent3)" }}>{subtitle}</span>
          </p>

          {/* Tagline */}
          <p className="hero-tagline">{tagline}</p>

          {/* CTAs */}
          <div className="hero-btns">
            <a href="mailto:chavanak870@gmail.com" className="btn-primary"
              onMouseEnter={e => { e.currentTarget.style.transform="translateY(-2px)"; e.currentTarget.style.boxShadow="0 8px 28px rgba(0,229,255,0.3)"; }}
              onMouseLeave={e => { e.currentTarget.style.transform="none"; e.currentTarget.style.boxShadow="none"; }}
            >✉ Get in Touch</a>
            <a href={`https://${contact.linkedin}`} target="_blank" rel="noreferrer" className="btn-outline"
              onMouseEnter={e => { e.currentTarget.style.borderColor="var(--accent2)"; e.currentTarget.style.color="var(--accent2)"; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor="var(--border)"; e.currentTarget.style.color="var(--text)"; }}
            >in LinkedIn</a>
          </div>
        </div>

        {/* Stats bar */}
        <div className="stats-wrap">
          <div className="stats-bar">
            {stats.map((s, i) => (
              <div key={i} className="stat-cell"
                onMouseEnter={e => e.currentTarget.style.background="var(--surface2)"}
                onMouseLeave={e => e.currentTarget.style.background="var(--surface)"}
              >
                <div className="stat-val">{s.value}</div>
                <div className="stat-lbl">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
}
